// demoSearchCmd returns mock dinosaur conversations, filtering by search term if provided.
func demoSearchCmd(searchTerm string) tea.Cmd {
	return func() tea.Msg {
		var re *regexp.Regexp
		if searchTerm != "" {
			var err error
			re, err = regexp.Compile(searchTerm)
			if err != nil {
				return searchErrorMsg{err: fmt.Errorf("invalid regex %q: %w", searchTerm, err)}
			}
		}

		var conversations []conversation
		for _, dc := range demoConversations {
			// Check if any message matches the search term
			hasMatch := re == nil
			if !hasMatch {
				for _, msg := range dc.messages {
					if re.MatchString(msg.text) {
						hasMatch = true
						break
					}
				}
			}
			if !hasMatch {
				continue
			}

			summary := dc.messages[0].text
			if len(summary) > 200 {
				summary = summary[:197] + "..."
			}

			conversations = append(conversations, conversation{
				sessionID:  dc.sessionID,
				cwd:        dc.cwd,
				summary:    summary,
				startedAt:  dc.startedAt,
				modifiedAt: dc.startedAt.Add(10 * time.Minute),
				demoMessages: dc.messages,
			})
		}

		sort.Slice(conversations, func(i, j int) bool {
			return conversations[i].modifiedAt.After(conversations[j].modifiedAt)
		})

		return searchResultsMsg{conversations: conversations}
	}
}
